		}
		if _, err := wt.Add("tracked.txt"); err != nil {
			tb.Fatalf("add file: %v", err)
		}
		if _, err := wt.Commit(fmt.Sprintf("commit %d", i), &git.CommitOptions{
			Author:    &defaultSignature,
			Committer: &defaultSignature,
		}); err != nil {
			tb.Fatalf("commit: %v", err)
		}
	}
}

