func (s *RefService) FetchCommitGraph(
	ctx context.Context,
	store storer.Storer,
	conn *Conn,
	ref DesiredRef,
	haves []plumbing.Hash,
) error {
	if s.Protocol != "v2" {
		return errors.New("commit graph fetch requires protocol v2")
